export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
	const findBound = (isFirst: boolean): number => {
		let low = 0;
		let high = values.length - 1;
		let result = -1;
		while (low <= high) {
			const mid = Math.floor(low + (high - low) / 2);
			if (values[mid] === target) {
				result = mid;
				if (isFirst) {
					high = mid - 1;
				} else {
					low = mid + 1;
				}
			} else if (values[mid] < target) {
				low = mid + 1;
			} else {
				high = mid - 1;
			}
		}
		return result;
	};

	const first = findBound(true);
	if (first === -1) {
		return [-1, -1];
	}
	const last = findBound(false);
	return [first, last];
}

