*   Goal: Implement `binarySearchFirstLastPosition(values: number[], target: number): [number, number]`.
    *   Input: A sorted array of numbers (`values`) and a target number (`target`).
    *   Output: A tuple `[firstIndex, lastIndex]` where `firstIndex` is the first occurrence of `target` and `lastIndex` is the last occurrence. If `target` is not found, return `[-1, -1]`.
    *   Constraint: The array is sorted.

    *   Since the array is sorted, we can use binary search to find the first and last positions.
    *   To find the first position:
        *   Perform binary search.
        *   If `values[mid] === target`, it *could* be the first position, but there might be an earlier one. So, record `mid` and continue searching in the left half (`high = mid - 1`).
        *   If `values[mid] < target`, search in the right half (`low = mid + 1`).
        *   If `values[mid] > target`, search in the left half (`high = mid - 1`).
    *   To find the last position:
        *   Perform binary search.
        *   If `values[mid] === target`, it *could* be the last position, but there might be a later one. So, record `mid` and continue searching in the right half (`low = mid + 1`).
        *   If `values[mid] < target`, search in the right half (`low = mid + 1`).
        *   If `values[mid] > target`, search in the left half (`high = mid - 1`).

    ```typescript
    export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
        let first = -1;
        let last = -1;

        // Find first position
        let low = 0;
        let high = values.length - 1;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (values[mid] === target) {
                first = mid;
                high = mid - 1; // Look left
            } else if (values[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        // If target not found, no need to look for last position
        if (first === -1) {
            return [-1, -1];
        }

        // Find last position
        low = 0;
        high = values.length - 1;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (values[mid] === target) {
                last = mid;
                low = mid + 1; // Look right
            } else if (values[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        return [first, last];
    }
