    class MinHeap {
        private heap: [number, number][] = [];

        push(val: [number, number]) {
            this.heap.push(val);
            this.bubbleUp();
        }

        pop(): [number, number] | undefined {
            if (this.size() === 0) return undefined;
            const top = this.heap[0];
            const bottom = this.heap.pop()!;
            if (this.size() > 0) {
                this.heap[0] = bottom;
                this.bubbleDown();
            }
            return top;
        }

        size() {
            return this.heap.length;
        }

        private bubbleUp() {
            let index = this.heap.length - 1;
            while (index > 0) {
                let parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] >= this.heap[parentIndex][0]) break;
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            }
        }

        private bubbleDown() {
            let index = 0;
            const length = this.heap.length;
            while (true) {
                let left = 2 * index + 1;
                let right = 2 * index + 2;
                let swap = -1;

                if (left < length) {
                    if (this.heap[left][0] < this.heap[index][0]) {
                        swap = left;
                    }
                }

                if (right < length) {
                    if (
                        (swap === -1 && this.heap[right][0] < this.heap[index][0]) ||
                        (swap !== -1 && this.heap[right][0] < this.heap[left][0])
